```cpp
#include <iostream>
#include <string>
#include <vector>

using namespace std;

// Define a struct to represent a clinic, police station, or company
struct Entity {
    string name;
    string address;
    int phone;
};

// Define a class to represent a database
class Database {
    vector<Entity> entities;
public:
    // Add a new entity to the database
    void addEntity(Entity entity) {
        entities.push_back(entity);
    }

    // Search for an entity in the database
    Entity searchEntity(string name) {
        for (int i = 0; i < entities.size(); i++) {
            if (entities[i].name == name) {
                return entities[i];
            }
        }
        return Entity();
    }
};

// Define main function to demonstrate usage of the database class
int main() {
    // Add some entities to the database
    Database database;
    database.addEntity({"Clinic A", "123 Main St", "555-1234"});
    database.addEntity({"Police Station B", "456 Elm St", "987-6543"});
    database.addEntity({"Company C", "789 Oak St", "000-0000"});

    // Search for an entity in the database
    Entity searchedEntity = database.searchEntity("Clinic A");
    cout << "Found entity: " << searchedEntity.name << endl;

    return 0;
}
```
This example defines a `Database` class that maintains a vector of `Entity` structs representing clinics, police stations, and companies. The `addEntity()` method can be used to add new entities to the database, and the `searchEntity()` method can be used to search for an entity based on its name.

In the `main()` function, we add some entities to the database, search for an entity using the `searchEntity()` method, and print the result to the console.

